class Solution:
    def findLength(self, nums1: list[int], nums2: list[int]) -> int:
        n = len(nums1)
        m = len(nums2)

        # dp[i][j] represents the length of the longest common subarray ending at nums1[i-1] and nums2[j-1]
        dp = [[0] * (m + 1) for _ in range(n + 1)]

        max_len = 0

        for i in range(1, n + 1):
            for j in range(1, m + 1):
                if nums1[i - 1] == nums2[j - 1]:
                    dp[i][j] = 1 + dp[i - 1][j - 1]
                    max_len = max(max_len, dp[i][j])
                # If characters don't match, the common subarray ending here is broken, so dp[i][j] remains 0
                # (it's already initialized to 0, so no explicit else block setting to 0 is needed here if it's not matching the previous condition)

        return max_len
